(function() {
    var rosAdditionalNoteController = function($scope, $http, $rootScope,$ocLazyLoad,$modal, $timeout,$modalInstance,rosAdditionalNoteService,initData) {
        $scope.additionalNotes = undefined;
        $scope.selectedTab = 1;
        $scope.guidanceImage = {
            observationImage:'data:image/jpg;base64,',
            showObservationsImage:false,
        }

        $scope.isMerge = false;
        $scope.isCopy = false;
        $scope.isDelete = false;
        $scope.isParentHasLock = false;
        var lockObj = {};

        $scope.initRosAdditionalNote = function() {
            $scope.patientId = initData.patientId;
            $scope.encounterId = initData.encounterId;
            lockObj = initData.lockObj;
            if(lockObj){
                $scope.isParentHasLock = true;
            }else {
                lockObj = {formName: "frmReview", uniqueKey: "frmReview" + $scope.encounterId, g_cancel: false, strKey: "", isOpenform: false};
                acquireFormLock(lockObj, function() {
                    if (lockObj.g_cancel) {
                        $scope.close();
                        return;
                    }
                });
            }
            $scope.loadAdditionalData();
            $('#rosAdditionalModal').modal();
        };

        $scope.loadAdditionalData = function(){
            var aPromise = rosAdditionalNoteService.getCategoryDetails(initData.encounterId, initData.patientId, 0);
            aPromise.then(function(object) {
                $scope.additionalNotes = {observations:[]};
                var x2js = new X2JS();
                var json = x2js.xml_str2json(object);
                var addNotes = json.Envelope.Body.return.additionalnotes;
                if(addNotes){
                    if(addNotes.observations){
                        $scope.additionalNotes.observations = $scope.returnArray(addNotes.observations.observation);
                        for(var index in $scope.additionalNotes.observations){
                            $scope.additionalNotes.observations[index].suggestedcategories = $scope.returnArray($scope.additionalNotes.observations[index].suggestedcategories.suggestedcategory);
                            $scope.additionalNotes.observations[index].enableCopyBtn = false;
                            $scope.additionalNotes.observations[index].enableMergeBtn = false;
                            if($scope.additionalNotes.observations[index].suggestedcategories.length>0 && $scope.additionalNotes.observations[index].suggestedcategories != ""){
                                $scope.additionalNotes.observations[index].suggestedCategoryId = $scope.additionalNotes.observations[index].suggestedcategories[0].suggestedCategoryId;
                                $scope.additionalNotes.observations[index].suggestedCategoryName = $scope.additionalNotes.observations[index].suggestedcategories[0].suggestedCategoryName;
                                $scope.additionalNotes.observations[index].enableCopyBtn = true;
                                $scope.additionalNotes.observations[index].enableMergeBtn = true;
                            }
                        }
                    }
                }
            });
        }

        $scope.returnArray = function(data){
            var response = [];
            if(Array.isArray(data)){
                response = data;
            }else{
                response.push(data);
            }
            return response;
        }

        $scope.close = function(){
            $modalInstance.close('success');
        }

        $scope.releaseLock = function(){
            var isClosed = false;
            if (lockObj.strKey !== "") {
                if (!isLockMine(lockObj)) {
                    isClosed = true;
                }
            }
            if(!isClosed && !$scope.isParentHasLock){
                releaseFormLock(lockObj)
            }
        }

        $scope.saveObservation = function(observation,isCopy){
            $scope.isCopy = false;
            $scope.isMerge = false;
            $scope.isDelete = false;
            if(isCopy){
                $scope.isCopy = true;
                showConfirmationPopup(observation,isCopy);
            }else{
                $scope.isMerge = true;
                showConfirmationPopup(observation,isCopy);
            }
        }

        function showConfirmationPopup(observation,isCopy){
            var modalInstance = $modal.open({
                templateUrl: makeURL('/mobiledoc/jsp/webemr/progressnotes/ros/ros-confirmation-popup.html'),
                scope: $scope,
                backdrop: 'static',
                keyboard: false,
                windowClass: 'confirmation-modal'
            });
            modalInstance.result.then(function (modalInstanceResponse) {
            }, function (modalInstanceResponse) {
                if(modalInstanceResponse){
                    if (lockObj.strKey !== "") {
                        if (!isLockMine2(lockObj)) {
                            $timeout(function(){
                                $scope.close();
                            }, 500);
                            return;
                        }
                    }
                    saveObservationCallback(observation, isCopy);
                }
            });
        }

        function saveObservationCallback(observation, isCopy) {
            rosAdditionalNoteService.saveObservation($scope.encounterId, observation.suggestedCategoryId, getSaveObservationJson(observation), isCopy).then(function (object) {
                    $scope.loadAdditionalData();
            }, function errorCallback(error) {
                ecwAlert("Some Error occurred while coping/merging unmapped data.Please try again later");
            });
        }

        var getSaveObservationJson = function(observation){
            return {"encounterId":observation.encounterId,"categoryId":observation.suggestedCategoryId,"itemId":observation.itemID, "value":replaceUTFCharWithASCII(observation.value), "value2":observation.value2, "presence":observation.presence, "displayIndex": observation.displayIndex};
        }

        var getDeleteObservationJson = function(observation){
            return {"encounterId":observation.encounterId,"itemId":observation.itemID, "categoryId" : 0};
        }

        function showConfirmationPopupDelete(observation){
            $scope.isDelete = true;
            var modalInstance = $modal.open({
                templateUrl: makeURL('/mobiledoc/jsp/webemr/progressnotes/ros/ros-confirmation-popup.html'),
                scope: $scope,
                backdrop: 'static',
                keyboard: false,
                windowClass: 'confirmation-modal'
            });
            modalInstance.result.then(function (modalInstanceResponse) {
            }, function (modalInstanceResponse) {
                if (modalInstanceResponse) {
                    if (lockObj.strKey !== "") {
                        if (!isLockMine2(lockObj)) {
                            $timeout(function(){
                                $scope.close();
                            }, 500);
                            return;
                        }
                    }
                    rosAdditionalNoteService.deleteObservation(getDeleteObservationJson(observation)).then(function (response) {
                        $scope.loadAdditionalData();
                    }, function errorCallback(error) {
                        ecwAlert("Some Error occurred while deleting unmapped data.Please try again later");
                    });
                }
            });
        }

        $scope.deleteObservation = function(observation){
            $scope.isCopy = false;
            $scope.isMerge = false;
            $scope.isDelete = false;
            showConfirmationPopupDelete(observation);
        }

        $scope.showObservationNotes = function(notes){
            $scope.currentObservationNotes = notes;
            if($scope.currentObservationNotes) {
                $("#additionalObservationNotesModal").modal({backdrop: "static", keyboard: false});
            }
        };

    }
    var rosAdditionalNoteService = function($http) {
        return {
            getCategoryDetails: function (encounterId, patientId, categoryId) {
                var url = '/mobiledoc/jsp/catalog/xml/getRos.jsp?encounterId=' + encounterId + '&patientId=' + patientId + '&Id=' + categoryId;
                url = makeURL(url);
                var aPromise = $http.get(url).then(function (response) {
                    return response.data;
                }, function (response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            },
            saveObservation: function (encounterId, examinationId, requestBody,isCopy) {
                var serverUrl = '/mobiledoc/clinicaldocumentation/ros/unmapped/items/false';
                if(isCopy === 0){
                    serverUrl = '/mobiledoc/clinicaldocumentation/ros/unmapped/items/true';
                }
                serverUrl = makeURL(serverUrl);
                var aPromise = $http({
                    headers: {'Content-Type': 'application/json'},
                    dataType: 'text',
                    method: 'POST',
                    url: serverUrl,
                    data: requestBody
                }).then(function(response) {
                    return  response.data;
                }, function(response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            },
            deleteObservation: function (requestBody) {
                var serverUrl = '/mobiledoc/clinicaldocumentation/ros/unmapped/observation/'
                serverUrl = makeURL(serverUrl);
                var aPromise = $http({
                    headers: {'Content-Type': 'application/json'},
                    dataType: 'text',
                    method: 'POST',
                    url: serverUrl,
                    data: requestBody
                }).then(function(response) {
                    return  response.data;
                }, function(response) {
                    throw "Internal Error occured, Please try after some time";
                });
                return aPromise;
            }
        }
    }
    var rosAdditionalNoteApp = angular.module("rosAdditionalNoteApp", ['ui.bootstrap','oc.lazyLoad']);
    rosAdditionalNoteApp.controller("rosAdditionalNoteController", rosAdditionalNoteController);
    rosAdditionalNoteApp.service('rosAdditionalNoteService', rosAdditionalNoteService);
})();